import * as Sentry from "@sentry/astro";

Sentry.init({
  dsn: "https://442ffed3c3b785924073d86c0eab95e7@o4511352978735104.ingest.de.sentry.io/4511451314978896",
  
  // 1. PERFORMANCE MONITORING
  // Captures 10% of user sessions to track Core Web Vitals and Web Audio lag issues
  tracesSampleRate: 0.1,

  // 2. PRIVACY & COMPLIANCE (Essential for Health Apps)
  // Ensures any data inside forms or text fields is stripped before being sent to Sentry
  sendDefaultPii: false, 

  beforeSend(event) {
    // Sanitize error messages just in case any user text gets captured
    if (event.exception && event.exception.values) {
      event.exception.values.forEach((value) => {
        if (value.value) {
          // Strips out potential user file paths or audio input names
          value.value = value.value.replace(/\/Users\/[^\/]+/g, "/Users/hidden_user");
        }
      });
    }
    return event;
  },

  // 3. AUDIO PERFORMANCE TRACKING
  integrations: [
    // Automatically tags the user's browser type, which is critical since 
    // audio latency differs wildly between Chrome (low latency) and other engines.
    Sentry.browserTracingIntegration(),
  ],
});